export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const survivors = cells.filter((cell) => survives(countAliveNeighbors(cell, aliveKeys)));

  const bornByKey = new Map<string, Cell>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = cellKey(neighbor);
      if (aliveKeys.has(k)) continue;
      if (bornByKey.has(k)) continue;
      if (countAliveNeighbors(neighbor, aliveKeys) === 3) {
        bornByKey.set(k, neighbor);
      }
    }
  }

  return [...survivors, ...bornByKey.values()];
}

